{
  "title": "हाइब्रिड खोज",
  "group": "पुनर्प्राप्ति",
  "options": [
    {
      "text": "एक ही क्वेरी को दो बार चलाना, अतिरिक्तता के लिए"
    },
    {
      "text": "एक ही कॉर्पस पर दो अलग-अलग एम्बेडिंग मॉडल का उपयोग करना"
    },
    {
      "text": "बेहतर पुनर्प्राप्ति के लिए वेक्टर खोज को कीवर्ड खोज के साथ मिलाना"
    },
    {
      "text": "एक साथ कई वेक्टर डेटाबेस में खोज करना"
    }
  ],
  "questionProse": [
    "RAG सिस्टम में, \"हाइब्रिड खोज\" का मतलब है:"
  ],
  "explanationProse": [
    "हाइब्रिड खोज **वेक्टर खोज** (एम्बेडिंग के माध्यम से अर्थपूर्ण समानता) और **कीवर्ड खोज** (BM25 / फुल‑टेक्स्ट सर्च) को मिलाती है क्योंकि वे पूरक रूप से विफल होते हैं:\n\n    - वेक्टर खोज को सटीक शब्दों में समस्या होती है: प्रोडक्ट नाम, एरर कोड, मॉडल नंबर, तकनीकी पहचानकर्ता\n    - कीवर्ड खोज को पैराफ्रेज़िंग में समस्या होती है: \"how do I cancel\" बनाम \"terminate subscription\"\n\n    दोनों के परिणाम **Reciprocal Rank Fusion (RRF)** का उपयोग करके मिलाए जाते हैं — एक रैंकिंग एल्गोरिद्म जो कई रैंक्ड लिस्टों की पोजीशन को बिना सामान्यीकृत स्कोर के जोड़ता है।\n\n    ये दोनों Postgres में `pgvector` + `tsvector` के साथ उपलब्ध हैं। आपको अलग सर्च सर्विस की ज़रूरत नहीं हो सकती।"
  ]
}
